var e=[{id:`L3_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`안녕? 넌 이름이 뭐야?`,JPN:`こんにちは！　お名前は？`,ENG:`Hi! What's your name?`,TWN:`你好？你叫什麼名字？`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`......스카이.`,JPN:`……スカイ。`,ENG:`... Sky.`,TWN:`……絲凱。`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`난 스카이 레이필드야.`,JPN:`私はスカイ・レイフィールドだよ。`,ENG:`I'm Sky Layfield.`,TWN:`我叫絲凱·蕾菲爾德。`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:null,text:{KOREA:`좋아, 스카이!`,JPN:`よし、スカイ！`,ENG:`Okay, Sky!`,TWN:`你好呀，絲凱！`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`우리랑 같이 안 놀래? 축구하려는데 마침 한 명이 모자랐거든!`,JPN:`私たちと一緒に遊ばない？　サッカーをしようとしたけどちょうど一人足りなくて！`,ENG:`Wanna play with us? We're one short for our soccer team!`,TWN:`你要不要跟我們一起玩啊？我們要踢足球，正好缺一個人！`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`응! 좋아!`,JPN:`うん！　いいよ！`,ENG:`Okay! I will!`,TWN:`嗯！好啊！`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:null,text:{KOREA:`앗! 거기! 공 좀 던져 줄래?`,JPN:`ねえ！　ボールを投げてくれない？`,ENG:`Oh! You over there! Could you pass me the ball?`,TWN:`啊！那個！你能把球扔過來嗎？`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:null,R:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`......여기.`,JPN:`……どうぞ。`,ENG:`... Here.`,TWN:`……這邊。`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:null,R:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L20_1`,type:`dialog`,speaker:null,text:{KOREA:`고마워!`,JPN:`ありがとう！`,ENG:`Thanks!`,TWN:`謝謝！`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:null,R:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:null,text:{KOREA:`......그런데 왜 혼자 여기서 쪼그려 앉아 있어?`,JPN:`……どうして一人でここにしゃがんでるの？`,ENG:`Hey, why are you sitting here alone?`,TWN:`……不過你怎麼一個人蹲在這兒啊？`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:null,R:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:null,text:{KOREA:`너도 우리랑 같이 놀래?`,JPN:`私たちと一緒に遊ばない？`,ENG:`Do you wanna play with us?`,TWN:`你要不要也跟我們一起玩呀？`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:null,R:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L24_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`그래도 돼?`,JPN:`そうしてもいいの？`,ENG:`Can I?`,TWN:`我可以嗎？`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:null,R:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L26_1`,type:`dialog`,speaker:null,text:{KOREA:`물론이지!`,JPN:`もちろん！`,ENG:`Sure!`,TWN:`當然！`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:null,R:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L27_1`,type:`dialog`,speaker:null,text:{KOREA:`......그런데, 넌 이름이 뭐야?`,JPN:`ところで、あなたの名前は？`,ENG:`Hey, what's your name?`,TWN:`……不過，你叫什麼名字呀？`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:null,R:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L29_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`난......`,JPN:`私は……`,ENG:`I'm...`,TWN:`我……`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`......스카이!`,JPN:`……スカイ！`,ENG:`Sky!`,TWN:`……絲凱！`},stage:{bg:`SCHOOL_SPRING`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};